// Route the user's chat message to the right executor.sh job
const chatInput = $input.first().json.chatInput || $input.first().json.body || '';

// Simple capability detection from message content
let capability = 'agent-general';
const msg = chatInput.toLowerCase();

if (msg.match(/\b(health|container|docker|service|infra|status|running|disk|memory|cpu|grafana|prometheus|caddy|loki)\b/)) {
  capability = 'agent-infra-check';
} else if (msg.match(/\b(research|search|find|look up|what is|how does|latest|version|docs|documentation)\b/)) {
  capability = 'agent-research';
} else if (msg.match(/\b(fix|troubleshoot|diagnose|broken|down|slow|error|issue|problem|restart|not working)\b/)) {
  capability = 'agent-troubleshoot';
}

// Escape single quotes in the prompt for shell safety
const safePrompt = chatInput.replace(/'/g, "'\\'");

// Build executor.sh command — UPDATE THIS PATH
const cmd = `${process.env.PROJECT_DIR || '/path/to/project'}/.claude/jobs/executor.sh --job ${capability} --param "prompt=${safePrompt}" --param "safety_mode=readonly" --quiet`;

return [{ json: { command: cmd, capability: capability, original_prompt: chatInput } }];

// Parse executor.sh JSON output and return clean response
const input = $input.first().json;
const stdout = input.stdout || '';
const stderr = input.stderr || '';

let response = '';
try {
  const result = JSON.parse(stdout);
  response = result.result || result.response || stdout;
} catch (e) {
  response = stdout || stderr || 'No output received from agent.';
}

if (input.exitCode && input.exitCode !== 0 && !response) {
  response = `Agent encountered an error (code ${input.exitCode}): ${stderr || 'Unknown error'}`;
}

return [{ json: { output: response } }];
